import android.content.Context;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKeys;

import java.io.IOException;
import java.security.GeneralSecurityException;
import java.security.KeyPairGenerator;
import java.security.KeyStore;
import java.util.Map;

public class CredentialsManager {

    private static final String PREFS_NAME = "LoginPrefs";
    private static final String EMAIL_KEY = "email";
    private static final String AUTH_TOKEN_KEY = "auth_token";

    private EncryptedSharedPreferences sharedPreferences;

    public CredentialsManager(Context context) {
        try {
            String masterKeyAlias = MasterKeys.getOrCreate(MasterKeys.AES256_GCM_SPEC);
            sharedPreferences = EncryptedSharedPreferences.create(
                    PREFS_NAME,
                    masterKeyAlias,
                    context,
                    EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                    EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            );
        } catch (GeneralSecurityException | IOException e) {
            throw new RuntimeException("Failed to initialize SharedPreferences", e);
        }
    }

    public void saveCredentials(String email, String authToken) {
        sharedPreferences.edit()
                .putString(EMAIL_KEY, email)
                .putString(AUTH_TOKEN_KEY, authToken)
                .apply();
    }

    public Map<String, ?> loadCredentials() {
        return sharedPreferences.getAll();
    }

    public void clearCredentials() {
        sharedPreferences.edit().clear().apply();
    }
}